struct StepRange {
    current: i32,
    end: i32,
    step: i32,
}

impl Iterator for StepRange {
    type Item = i32;
    fn next(&mut self) -> Option<i32> {
        if self.current >= self.end {
            return None;
        }
        let val = self.current;
        self.current += self.step;
        Some(val)
    }
}

// IntoIterator with Self as the iterator type (the type IS its own iterator)
impl IntoIterator for StepRange {
    type Item = i32;
    type IntoIter = StepRange;  // consumes self
    fn into_iter(self) -> StepRange {
        self  // iterator IS the range
    }
}

fn make_range(start: i32, end: i32, step: i32) -> StepRange {
    StepRange { current: start, end, step }
}

fn main() {
    for x in make_range(0, 10, 2) {
        println!("{}", x);
    }
    // Can also use Iterator methods after into_iter()
    let sum: i32 = make_range(1, 6, 1).sum();
    println!("sum: {}", sum);
}

