struct Tree {
    value: i32,
    children: Vec<Tree>,
}

struct PreOrderIter<'a> {
    stack: Vec<&'a Tree>,
}

impl<'a> Iterator for PreOrderIter<'a> {
    // Choose: yield &i32 (borrowing) or i32 (copying). Since i32: Copy, both are fine.
    type Item = &'a i32;

    fn next(&mut self) -> Option<&'a i32> {
        let node = self.stack.pop()?;
        for child in node.children.iter().rev() {
            self.stack.push(child);
        }
        Some(&node.value)
    }
}

impl Tree {
    fn iter(&self) -> PreOrderIter<'_> {
        PreOrderIter { stack: vec![self] }
    }
}

fn main() {
    let tree = Tree { value: 1, children: vec![
        Tree { value: 2, children: vec![] },
        Tree { value: 3, children: vec![] },
    ]};
    // Collect &i32 references, or use .copied() to get i32
    let vals: Vec<i32> = tree.iter().copied().collect();
    println!("{:?}", vals);
