fixed_code:
struct Bag<T> {
    items: Vec<T>,
}

// By value: consumes the Bag
impl<T> IntoIterator for Bag<T> {
    type Item = T;
    type IntoIter = std::vec::IntoIter<T>;
    fn into_iter(self) -> Self::IntoIter {
        self.items.into_iter()
    }
}

// By shared reference: borrows the Bag
impl<'a, T> IntoIterator for &'a Bag<T> {
    type Item = &'a T;
    type IntoIter = std::slice::Iter<'a, T>;
    fn into_iter(self) -> Self::IntoIter {
        self.items.iter()
    }
}

// By mutable reference: mutably borrows the Bag
impl<'a, T> IntoIterator for &'a mut Bag<T> {
    type Item = &'a mut T;
    type IntoIter = std::slice::IterMut<'a, T>;
    fn into_iter(self) -> Self::IntoIter {
        self.items.iter_mut()
    }
}

fn main() {
    let mut bag = Bag { items: vec![1i32, 2, 3] };
    for x in &bag { println!("{}", x); }        // borrows
    for x in &mut bag { *x *= 2; }             // mutable borrow
    for x in bag { println!("{}", x); }        // consumes
}

